import React from 'react';
import { useNavigate } from 'react-router-dom'; // Add this import
import { History as HistoryIcon, PlusCircle } from 'lucide-react';

export default function Dashboard() {
  const navigate = useNavigate(); // Initialize navigation

  return (
    <div className="p-10 space-y-10">
      {/* Dashboard Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-4xl font-black text-slate-900">Community Dashboard</h1>
          <p className="text-slate-500 font-medium">Welcome back! Here's what's happening in <span className="text-teal-600 font-bold">Kochi</span> today.</p>
        </div>
        
        <div className="flex gap-4">
          {/* History Button Logic */}
          <button 
            onClick={() => navigate('/history')}
            className="flex items-center gap-2 px-6 py-3 bg-white border border-slate-100 text-slate-600 rounded-2xl font-bold hover:bg-slate-50 transition-all shadow-sm"
          >
            <HistoryIcon size={18} /> History
          </button>

          {/* New Listing Button Logic */}
          <button 
            onClick={() => navigate('/create')}
            className="flex items-center gap-2 px-6 py-3 bg-teal-600 text-white rounded-2xl font-bold hover:bg-teal-700 transition-all shadow-lg shadow-teal-600/20"
          >
            <PlusCircle size={18} /> New Listing
          </button>
        </div>
      </div>

      {/* Stats Section seen in image_b68765 */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="bg-slate-900 text-white p-8 rounded-[40px] shadow-xl">
           <p className="text-[10px] font-black uppercase tracking-widest text-teal-400 mb-4">Available Tokens</p>
           <h2 className="text-5xl font-black">1,450 <span className="text-xl text-slate-400">WTK</span></h2>
           <p className="text-teal-400 text-xs mt-4 font-bold">↗ +120 earned this week</p>
        </div>
        {/* ... other stat cards */}
      </div>
    </div>
  );
}
